import{_ as t,c as o,o as a,ag as d}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"DAG Adapters Local Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-adapters-local/SPEC.md","filePath":"packages/dag-adapters-local/SPEC.md"}'),r={name:"packages/dag-adapters-local/SPEC.md"};function s(c,e,i,n,l,p){return a(),o("div",null,e[0]||(e[0]=[d('<h1 id="dag-adapters-local-specification" tabindex="-1">DAG Adapters Local Specification <a class="header-anchor" href="#dag-adapters-local-specification" aria-label="Permalink to &quot;DAG Adapters Local Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p><code>@robota-sdk/dag-adapters-local</code> provides lightweight local implementations of port interfaces defined by <code>@robota-sdk/dag-core</code> and <code>@robota-sdk/dag-cost</code>. These adapters include both in-memory implementations (for state that does not need persistence) and file-based implementations (for state that should survive process restarts). They are designed for local development, testing, single-machine deployment, and demos where external infrastructure (databases, message queues, distributed locks) is not needed.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li><strong>In-memory adapters have no persistence.</strong> State is held in memory and lost on process restart.</li><li><strong>File-based adapters use local filesystem only.</strong> No network or cloud storage.</li><li><strong>No distributed semantics.</strong> Lease and queue implementations are single-process only.</li><li><strong>No domain logic.</strong> This package implements port interfaces; it does not define or extend domain contracts.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Dependency</th><th>Purpose</th></tr></thead><tbody><tr><td><code>@robota-sdk/dag-core</code></td><td>Port interface definitions (<code>IStoragePort</code>, <code>IQueuePort</code>, <code>ILeasePort</code>, <code>IClockPort</code>, <code>ITaskExecutorPort</code>)</td></tr><tr><td><code>@robota-sdk/dag-cost</code></td><td>Cost meta port interface (<code>ICostMetaStoragePort</code>, <code>ICostMeta</code>)</td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Implements</th><th>Description</th></tr></thead><tbody><tr><td><code>InMemoryStoragePort</code></td><td>Class</td><td><code>IStoragePort</code></td><td>In-memory storage for DAG definitions, runs, and tasks</td></tr><tr><td><code>InMemoryQueuePort</code></td><td>Class</td><td><code>IQueuePort</code></td><td>In-memory message queue (enqueue, dequeue, ack, nack)</td></tr><tr><td><code>InMemoryLeasePort</code></td><td>Class</td><td><code>ILeasePort</code></td><td>In-memory lease management (acquire, renew, release)</td></tr><tr><td><code>SystemClockPort</code></td><td>Class</td><td><code>IClockPort</code></td><td>Real system clock (<code>Date.now()</code>)</td></tr><tr><td><code>FakeClockPort</code></td><td>Class</td><td><code>IClockPort</code></td><td>Deterministic clock for tests (manually advance time)</td></tr><tr><td><code>MockTaskExecutorPort</code></td><td>Class</td><td><code>ITaskExecutorPort</code></td><td>Configurable mock for task execution</td></tr><tr><td><code>TTaskExecutorHandler</code></td><td>Type</td><td>--</td><td>Handler function type for <code>MockTaskExecutorPort</code></td></tr><tr><td><code>createStubPromptBackend</code></td><td>Function</td><td>--</td><td>Factory for stub prompt backend used in node testing</td></tr><tr><td><code>FileStoragePort</code></td><td>Class</td><td><code>IStoragePort</code></td><td>File-based JSON storage for DAG definitions, runs, and tasks</td></tr><tr><td><code>FileCostMetaStorage</code></td><td>Class</td><td><code>ICostMetaStoragePort</code></td><td>File-based JSON storage for cost metadata</td></tr></tbody></table><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li><strong>Unit / integration tests:</strong> Deterministic, fast, no external setup required.</li><li><strong>Local development:</strong> Run the full DAG pipeline on a single machine without Docker or external services.</li><li><strong>Demos and prototyping:</strong> Quick start with zero infrastructure.</li></ul><h2 id="future-direction" tabindex="-1">Future Direction <a class="header-anchor" href="#future-direction" aria-label="Permalink to &quot;Future Direction&quot;">​</a></h2><p>Production-grade adapters for external infrastructure will follow the same port-adapter pattern in separate packages:</p><ul><li><code>dag-adapters-mongodb</code> -- MongoDB persistence adapter</li><li><code>dag-adapters-redis</code> -- Redis queue and lease adapters</li><li><code>dag-adapters-postgresql</code> -- PostgreSQL persistence adapter</li></ul><p>Each adapter package will depend on <code>dag-core</code> for port interfaces and its respective driver library.</p>',15)]))}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
